import React from "react";

export default function NotificationsPopup({ notifications, open, onClose }) {
  if (!open) return null;

  return (
    <div
      style={{
        position: "fixed",
        top: 50,
        right: 20,
        width: 320,
        background: "white",
        borderRadius: 10,
        boxShadow: "0 2px 12px rgba(0,0,0,0.15)",
        zIndex: 1000,
        maxHeight: "400px",
        overflowY: "auto",
      }}
    >
      <div
        style={{
          padding: "10px 16px",
          borderBottom: "1px solid #ddd",
          fontWeight: 600,
          fontSize: 16,
        }}
      >
        Notifications for Today
        <button
          onClick={onClose}
          style={{
            float: "right",
            cursor: "pointer",
            border: "none",
            background: "none",
            fontSize: 20,
          }}
        >
          ×
        </button>
      </div>
      {notifications.length === 0 && (
        <div style={{ padding: "15px", fontSize: 14, color: "#666" }}>
          No notifications today.
        </div>
      )}
      <ul style={{ listStyle: "none", margin: 0, padding: "10px 16px" }}>
        {notifications.map((note, idx) => (
          <li
            key={idx}
            style={{ padding: "8px 0", borderBottom: "1px solid #eee" }}
          >
            {note}
          </li>
        ))}
      </ul>
    </div>
  );
}
